#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    int len;
    int cap;
} Vec;

Vec vec_new(void) {
    return (Vec){NULL, 0, 0};
}

void vec_push(Vec *v, int val) {
    if (v->len == v->cap) {
        int new_cap = v->cap == 0 ? 4 : v->cap * 2;
        int *tmp = realloc(v->data, new_cap * sizeof(int));
        if (!tmp) return;
        v->data = tmp;
        v->cap = new_cap;
    }
    v->data[v->len] = val;
    v->len++;
}

void vec_free(Vec *v) {
    free(v->data);
    v->data = NULL;
    v->len = v->cap = 0;
}

int main(void) {
    Vec v = vec_new();
    for (int i = 0; i < 10; i++) vec_push(&v, i*i);
    printf("len=%d cap=%d\n", v.len, v.cap);
    printf("contenu:");
    for (int i = 0; i < v.len; i++) printf(" %d", v.data[i]);
    printf("\n");
    vec_free(&v);
    return 0;
}

