/* == EXEMPLE ================================================
 * Buffer de chars avec croissance x2
 * Montre le pattern realloc dans un temporaire.
 * =========================================================== */
typedef struct { char *buf; int len, cap; } CharBuf;

void example_append(CharBuf *b, char c) {
    if (b->len == b->cap) {
        int nc = b->cap == 0 ? 4 : b->cap * 2;
        char *tmp = realloc(b->buf, nc);
        if (!tmp) return;
        b->buf = tmp; b->cap = nc;
    }
    b->buf[b->len++] = c;
}
void example_demo(void) {
    CharBuf b = {NULL, 0, 0};
    const char *s = "Hello";
    for (int i = 0; s[i]; i++) example_append(&b, s[i]);
    example_append(&b, '\0');
    printf("%s (len=%d cap=%d)\n", b.buf, b.len, b.cap);
    free(b.buf);
}
